#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
LL T,l,r,L[50],R[50],Bas[50];
LL UP=40,sum,now,ans;bool flag;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int main(){
    T=read();
    while(T--){
        l=read(),r=read();
        Bas[0]=1ll,sum=0,ans=0,now=0,flag=0;
        for(LL i=1;i<=UP+1;i++)Bas[i]=Bas[i-1]*3ll;
        for(LL i=0;i<=UP;i++)
            L[i]=l%Bas[i+1]/Bas[i],R[i]=r%Bas[i+1]/Bas[i];
        for(LL i=UP;i>=0;i--){
            if(R[i])flag=1;if(!flag)continue;
            if(R[i]&&now+R[i]*Bas[i]>l)
                if(R[i]>1||sum)ans=max(ans,sum+R[i]+3ll*i);
                else ans=max(ans,sum+3ll*i);
            sum+=R[i]+1ll,now+=R[i]*Bas[i];
        }cout<<max(ans,sum)<<"\n";
    }
    return 0;
}
